# app/mailers/sendgrid_mailer.rb
class SendgridMailer < ApplicationMailer
  def deliver_email(to:, subject:, template_name:, assigns: {}, from: nil, reply_to: nil)
    assigns.each { |key, value| instance_variable_set("@#{key}", value) }

    mail(
      to: to,
      from: from || default_params[:from],
      reply_to: reply_to,
      subject: subject,
      template_name: template_name
    )
  end

  def welcome_email(user)
    @user = user

    mail(
      to: @user.email,
      subject: 'Welcome',
      from: default_params[:from]
    )
  end
end

